const rows = $input.all().map((item) => item.json ?? item);
const retryableCategories = new Set(['transient', 'provider', 'database']);
const retryable = rows.filter((row) => retryableCategories.has(String(row.failureCategory || '').toLowerCase()) && !['signature', 'schema', 'validation', 'auth'].includes(String(row.failureCategory || '').toLowerCase()));
return [{ json: { retryableIds: retryable.map((row) => row.jobId), retryableIdsJson: JSON.stringify(retryable.map((row) => row.jobId)), retryableCount: retryable.length, blockedCount: rows.length - retryable.length } }];
